package main

import (
	"encoding/gob"
	"fmt"
	"os"
)

type UserSession struct {
	ID       int
	Prefs    map[string]interface{}
	Perms    []string
}

func main() {
	// Load user sessions from disk
	var sessions []UserSession
	file, err := os.Open("sessions.gob")
	if err != nil {
		fmt.Println(err)
		return
	}
	defer file.Close()
	decoder := gob.NewDecoder(file)
	err = decoder.Decode(&sessions)
	if err != nil {
		fmt.Println(err)
		return
	}

	// Handle user requests
	for _, session := range sessions {
		fmt.Printf("User %d with preferences %v and permissions %v\n", session.ID, session.Prefs, session.Perms)
	}

	// Save user sessions to disk
	file, err = os.Create("sessions.gob")
	if err != nil {
		fmt.Println(err)
		return
	}
	defer file.Close()
	encoder := gob.NewEncoder(file)
	err = encoder.Encode(&sessions)
	if err != nil {
		fmt.Println(err)
		return
	}
}